TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
@x = qw(A r h);
Context("Fraction")->variables->are(map {$_ => 'Real'} (@x));
$left = Formula("A")->reduce;
$right = Formula("2 pi r^2 + 2 pi r h")->reduce;
parser::Assignment->Allow;
$ans = Assignment("h = (A - 2 pi r^2)/(2 pi r)");

$introduction_image_1 = createLaTeXImage();
$introduction_image_1->addToPreamble(latexImagePreamble());
$introduction_image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \draw[fill=firstcolor!20] (0,0) ellipse (3 and 0.45);
  \draw[fill=firstcolor!10] (3,0) arc (0:180:3 and -0.45) -- (-3,-2) arc (180:360:3 and 0.5) -- cycle;
  \draw [dashed] (-3,-2) arc (180:360:3 and -0.5);
  \draw [dashed] (0,0) -- (3,0) node[pos=0.5,above] {radius \(r\)};
  \node at (-3,-1) [left] {height \(h\)};
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
The volume of a cylinder can be found with the equation [`V=\pi r^2h\text{,}`] where [`r`] is the radius and [`h`] is the height. Its surface area can be found with the equation [`A=2\pi r^2+2\pi rh\text{.}`]

>> [@image(insertGraph($introduction_image_1), width=>300)@]*  <<

Solve [`[$left]=[$right]`] for [`h\text{.}`]

[@KeyboardInstructions('You may type [`\pi`] as [|pi|]* or [|π|]*.')@]**

[_]{$ans}{16}

END_PGML

